    fn id_of_ref_edge(&self, r: &EdgeRef) -> u64 {
        match r {
            EdgeRef::Edge(i) => self.edge_ids[i.0].expect("dep id assigned"),
            EdgeRef::EdgeCurve(i) => self.edge_curve_ids[i.0].expect("dep id assigned"),
            EdgeRef::OrientedEdge(i) => self.oriented_edge_ids[i.0].expect("dep id assigned"),
            EdgeRef::Complex(i) => self.complex_ids[i.0].expect("dep id assigned"),
        }
    }

    fn deps_ref_edge(r: &EdgeRef, out: &mut Vec<AnyId>) {
        match r {
            EdgeRef::Edge(i) => out.push(AnyId::Edge(*i)),
            EdgeRef::EdgeCurve(i) => out.push(AnyId::EdgeCurve(*i)),
            EdgeRef::OrientedEdge(i) => out.push(AnyId::OrientedEdge(*i)),
            EdgeRef::Complex(i) => out.push(AnyId::ComplexUnit(*i)),
        }
    }

