    fn id_of_ref_transformation(&self, r: &TransformationRef) -> u64 {
        match r {
            TransformationRef::FunctionallyDefinedTransformation(i) => {
                self.functionally_defined_transformation_ids[i.0].expect("dep id assigned")
            }
            TransformationRef::ItemDefinedTransformation(i) => {
                self.item_defined_transformation_ids[i.0].expect("dep id assigned")
            }
            TransformationRef::Complex(i) => self.complex_ids[i.0].expect("dep id assigned"),
            TransformationRef::SetItemDefinedTransformation(_) => {
                panic!("aggregate via single id_of")
            }
            TransformationRef::ListItemDefinedTransformation(_) => {
                panic!("aggregate via single id_of")
            }
        }
    }

    fn deps_ref_transformation(r: &TransformationRef, out: &mut Vec<AnyId>) {
        match r {
            TransformationRef::FunctionallyDefinedTransformation(i) => {
                out.push(AnyId::FunctionallyDefinedTransformation(*i))
            }
            TransformationRef::ItemDefinedTransformation(i) => {
                out.push(AnyId::ItemDefinedTransformation(*i))
            }
            TransformationRef::Complex(i) => out.push(AnyId::ComplexUnit(*i)),
            TransformationRef::SetItemDefinedTransformation(vs) => {
                for e in vs {
                    Self::deps_ref_item_defined_transformation(e, out);
                }
            }
            TransformationRef::ListItemDefinedTransformation(vs) => {
                for e in vs {
                    Self::deps_ref_item_defined_transformation(e, out);
                }
            }
        }
    }

